import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface QuarterlyComparison {
  quarter: string;
  profitMargin: number;
}

interface ProfitMarginData {
  currentQuarter: {
    profit: number;
    revenue: number;
    margin: number;
  };
  previousQuarter: {
    profit: number;
    revenue: number;
    margin: number;
  };
  quarterlyComparison: QuarterlyComparison[];
}

interface Meta {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
}

export default function Widget() {
  const data = response.data as ProfitMarginData;
  const meta = response.meta as Meta;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={700} sx={{ color: meta.primaryColor }}>
              Profit Margin
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Current Quarter
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#10B981' }}>
              {data.currentQuarter.margin}%
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Previous Quarter: {data.previousQuarter.margin}%
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: data.quarterlyComparison.map(q => q.profitMargin),
                  color: meta.accentColor,
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.quarterlyComparison.map(q => q.quarter),
                  id: 'quarters',
                },
              ]}
              yAxis={[{ id: 'margin' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="quarters"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="margin"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
